-- BuilderTrend import — bt-invoices batch 4 of 4  (2638 rows)
-- Run batches strictly in order.
BEGIN;
CREATE TABLE IF NOT EXISTS _bt_inv_stg (
  bt_invoice_id bigint, bt_job_id bigint, invoice_number text, title text,
  amount numeric, amount_paid numeric, invoice_date date, due_date date,
  paid_status text, status text
);
DO $$
DECLARE r record; v_job uuid; n_ins int := 0; n_skip int := 0;
BEGIN
  FOR r IN SELECT * FROM _bt_inv_stg LOOP
    SELECT id INTO v_job FROM jobs WHERE bt_job_id = r.bt_job_id LIMIT 1;
    IF v_job IS NULL THEN n_skip := n_skip + 1; CONTINUE; END IF;
    IF EXISTS (SELECT 1 FROM job_invoices WHERE bt_invoice_id = r.bt_invoice_id) THEN
      n_skip := n_skip + 1; CONTINUE;
    END IF;
      amount_paid, invoice_date, due_date, paid_status, status, is_manual, source)
    VALUES (v_job, r.bt_invoice_id, r.invoice_number, r.title, r.amount,
      r.amount_paid, COALESCE(r.invoice_date, CURRENT_DATE), r.due_date,
      r.paid_status, r.status, true, 'buildertrend');
    n_ins := n_ins + 1;
  END LOOP;
  RAISE NOTICE 'job_invoices imported: %, skipped (no job / dup): %', n_ins, n_skip;
END $$;
DROP TABLE _bt_inv_stg;
COMMIT;
